// agentActivityInput bundles the parameters common to all agent activities.
type agentActivityInput[T any] struct {
	script       string
	taskID       string
	parentSpanID string
	input        any
	outputPath   string
	bodyField    string
	validate     func(T) error
}

// maxValidationRetries is the number of additional attempts after the first
// validation failure. The agent gets explicit feedback about what went wrong.
const maxValidationRetries = 1

// runAgentActivity is a generic helper that runs an agent, reads its output
// file, unmarshals the artifact, and validates it. Validation failures trigger
// an internal retry with the error message injected into the agent's prompt
// (up to maxValidationRetries extra attempts). Infrastructure errors (process
// crash, timeout) are returned immediately for Temporal to retry.
func runAgentActivity[T any](
	ctx context.Context,
	a *SwarmActivities,
	p agentActivityInput[T],
) (T, error) {
	var zero T

	// Resolve outputPath relative to repoRoot so Go reads from the same
	// absolute path that the JS agent writes to (its cwd is repoRoot).
	absOutputPath := p.outputPath
	if !filepath.IsAbs(absOutputPath) {
		absOutputPath = filepath.Join(a.repoRoot, absOutputPath)
	}

	// Ensure output directory exists.
	if err := os.MkdirAll(filepath.Dir(absOutputPath), 0o750); err != nil {
		return zero, fmt.Errorf("create output dir: %w", err)
	}

	// Build optional agent config from SwarmConfig.
	var agentCfg *AgentConfig
	if a.config.Model != "" {
		agentCfg = &AgentConfig{Model: a.config.Model}
	}

	var lastValErr error
	var lastOutput string

	for attempt := 0; attempt <= maxValidationRetries; attempt++ {
		// Build retry context for validation retries (attempt > 0).
		var retryCtx *RetryContext
		if attempt > 0 && lastValErr != nil {
			retryCtx = &RetryContext{
				Attempt:         attempt + 1,
				ValidationError: lastValErr.Error(),
				PriorOutput:     truncate(lastOutput, maxJSONLen),
			}
			a.logger.Warn("retrying agent with validation feedback",
				"script", p.script,
				"attempt", attempt+1,
				"error", lastValErr)
		}

		_, err := runAgent(ctx, runAgentParams{
			script:         p.script,
			taskID:         p.taskID,
			parentSpanID:   p.parentSpanID,
			input:          p.input,
			projectContext: a.projectContext,
			repoRoot:       a.repoRoot,
			outputPath:     absOutputPath,
			runner:         a.runner,
			database:       a.db,
			eventBus:       a.eventBus,
			logger:         a.logger,
			toolCallLimit:  a.config.ToolCallLimit,
			agentConfig:    agentCfg,
			retryContext:   retryCtx,
			heartbeat: func(details any) {
				activity.RecordHeartbeat(ctx, details)
			},
		})
		if err != nil {
			// Infrastructure error — let Temporal retry.
			return zero, fmt.Errorf("%s: %w", p.script, err)
		}

		// Format output file (normalize YAML front matter + markdown).
		if fmtErr := formatArtifact(absOutputPath); fmtErr != nil {
			a.logger.Warn("mdformat failed, proceeding with raw file",
				"error", fmtErr, "path", absOutputPath)
		}

		// Parse output file.
		artifact, unmarshalErr := unmarshalArtifact[T](absOutputPath, p.bodyField)
		if unmarshalErr != nil {
			lastValErr = unmarshalErr
			lastOutput = readOutputFile(absOutputPath)
			continue // retry with feedback
		}

		// Validate.
		if p.validate != nil {
			if valErr := p.validate(artifact); valErr != nil {
				lastValErr = valErr
				lastOutput = readOutputFile(absOutputPath)
				continue // retry with feedback
			}
		}

		return artifact, nil
	}

	// Exhausted validation retries — mark non-retryable so Temporal doesn't
	// also retry with identical context.
	return zero, temporal.NewNonRetryableApplicationError(
		fmt.Sprintf("%s validation failed after %d attempts: %v",
			p.script, maxValidationRetries+1, lastValErr),
		"VALIDATION_EXHAUSTED", lastValErr,
	)
}

// readOutputFile reads the output file contents for inclusion in retry context.
// Returns empty string on error (best-effort).
func readOutputFile(path string) string {
	data, err := os.ReadFile(path)
	if err != nil {
		return ""
	}
	return string(data)
}

