	relationType string,
) (string, error) {
	if a.LinearClient == nil || parentID == "" {
		return "", nil
	}
	identifier, err := a.LinearClient.CreateIssue(ctx, title, linear.CreateOpts{
		Labels:      []string{"type:research"},
