package linear

// Issue represents a Linear issue returned by the CLI.
type Issue struct {
	ID          string `json:"id"`
	Identifier  string `json:"identifier"`
	Title       string `json:"title"`
	Description string `json:"description"`
	URL         string `json:"url"`
	State       State  `json:"state"`
	Labels      Labels `json:"labels"`
	Priority    int    `json:"priority"`
}

// State is the workflow state of an issue.
type State struct {
	Name string `json:"name"`
	Type string `json:"type"` // backlog, unstarted, started, completed, canceled
}

// Labels wraps the nested nodes array from linear-cli JSON output.
type Labels struct {
	Nodes []Label `json:"nodes"`
}

// Label is a single label on an issue.
type Label struct {
	ID    string `json:"id"`
	Name  string `json:"name"`
	Color string `json:"color"`
}

// Relation represents a relationship between two issues.
type Relation struct {
	Type       string `json:"type"`       // blocks, blocked-by, related
	Identifier string `json:"identifier"` // the related issue's identifier
}

// CreateOpts holds optional fields for creating an issue.
type CreateOpts struct {
	Team        string
	Priority    int
	Labels      []string
	State       string
	Description string
}

// SearchResult represents an issue returned by search.
type SearchResult struct {
	ID         string `json:"id"`
	Identifier string `json:"identifier"`
	Title      string `json:"title"`
	State      State  `json:"state"`
}

package linear

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"os/exec"
	"strconv"
	"strings"
)

// Client wraps the linear-cli binary for Linear API operations.
type Client struct {
	binaryPath string
	teamKey    string // e.g. "CRE"
}

// NewClient creates a new Linear CLI client. Returns nil if binaryPath is empty.
func NewClient(binaryPath, teamKey string) *Client {
	if binaryPath == "" {
		return nil
	}
	return &Client{
		binaryPath: binaryPath,
		teamKey:    teamKey,
	}
}

// run executes a linear-cli command and returns stdout bytes.
func (c *Client) run(ctx context.Context, args ...string) ([]byte, error) {
	cmd := exec.CommandContext(ctx, c.binaryPath, args...)
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr
	if err := cmd.Run(); err != nil {
		return nil, fmt.Errorf(
			"linear-cli %s: %w (stderr: %s)",
			strings.Join(args, " "),
			err,
			stderr.String(),
		)
	}
	return stdout.Bytes(), nil
}

// runJSON executes a linear-cli command with JSON output and unmarshals into T.
func runJSON[T any](c *Client, ctx context.Context, args ...string) (T, error) {
	var zero T
	args = append(args, "--output", "json", "--compact", "--quiet")
	data, err := c.run(ctx, args...)
	if err != nil {
		return zero, err
	}
	if err := json.Unmarshal(data, &zero); err != nil {
		return zero, fmt.Errorf(
			"parse linear-cli output: %w (raw: %s)",
			err,
			string(data),
		)
	}
	return zero, nil
}

// GetIssue fetches a single issue by identifier (e.g. "CRE-15").
func (c *Client) GetIssue(ctx context.Context, identifier string) (*Issue, error) {
	issue, err := runJSON[Issue](c, ctx, "issues", "get", identifier)
	if err != nil {
		return nil, err
	}
	return &issue, nil
}

// UpdateStatus changes the workflow state on an issue.
func (c *Client) UpdateStatus(ctx context.Context, identifier, status string) error {
	_, err := c.run(ctx, "issues", "update", identifier, "--state", status, "--quiet")
	return err
}

// UpdateLabels sets labels on an issue. The -l flag can be specified multiple times.
func (c *Client) UpdateLabels(
	ctx context.Context,
	identifier string,
	labels []string,
) error {
	args := make([]string, 0, 4+2*len(labels)) //nolint:mnd // base args + label pairs
	args = append(args, "issues", "update", identifier, "--quiet")
	for _, l := range labels {
		args = append(args, "-l", l)
	}
	_, err := c.run(ctx, args...)
	return err
}

// AddComment posts a markdown comment to an issue.
func (c *Client) AddComment(ctx context.Context, identifier, body string) error {
	_, err := c.run(ctx, "comments", "create", identifier, "--body", body, "--quiet")
	return err
}

// CreateAttachment links a URL to an issue as an attachment.
func (c *Client) CreateAttachment(
	ctx context.Context,
	identifier, title, url string,
) error {
	_, err := c.run(
		ctx,
		"attachments",
		"create",
		identifier,
		"--title",
		title,
		"--url",
		url,
		"--quiet",
	)
	return err
}

// CreateIssue creates a new issue and returns its identifier.
func (c *Client) CreateIssue(
	ctx context.Context,
	title string,
	opts CreateOpts,
) (string, error) {
	args := []string{"issues", "create", title}
	team := opts.Team
	if team == "" {
		team = c.teamKey
	}
	if team != "" {
		args = append(args, "--team", team)
	}
	if opts.Priority > 0 {
		args = append(args, "--priority", strconv.Itoa(opts.Priority))
	}
	if opts.State != "" {
		args = append(args, "--state", opts.State)
	}
	for _, l := range opts.Labels {
		args = append(args, "-l", l)
	}
	if opts.Description != "" {
		args = append(args, "--description", opts.Description)
	}
	args = append(args, "--id-only", "--quiet")

	data, err := c.run(ctx, args...)
	if err != nil {
		return "", err
	}
	// --id-only returns the identifier on stdout
	return strings.TrimSpace(string(data)), nil
}

// SearchIssues searches for issues matching a query string.
func (c *Client) SearchIssues(ctx context.Context, query string) ([]SearchResult, error) {
	results, err := runJSON[[]SearchResult](c, ctx, "search", "issues", query)
	if err != nil {
		return nil, err
	}
	return results, nil
}

// AddRelation creates a relationship between two issues.
// relationType must be "blocks", "blocked-by", or "related".
func (c *Client) AddRelation(ctx context.Context, from, relationType, to string) error {
	_, err := c.run(
		ctx,
		"relations",
		"add",
		from,
		to,
		"--relation",
		relationType,
		"--quiet",
	)
	return err
}

// ListRelations returns all relationships for an issue.
func (c *Client) ListRelations(
	ctx context.Context,
	identifier string,
) ([]Relation, error) {
	return runJSON[[]Relation](c, ctx, "relations", "list", identifier)
}

package server

import (
	"context"
	"database/sql"
	"encoding/json"
	"errors"
	"fmt"
	"net/http"
	"time"

	"github.com/google/uuid"
	"github.com/labstack/echo/v4"

	"creative-mode/harness/internal/db/sqlc"
	"creative-mode/harness/internal/linear"
	"creative-mode/harness/internal/swarmorch"
)

// workflowStarter abstracts the SwarmManager method used to start a workflow.
type workflowStarter func(ctx context.Context, taskID, requestText, ticketID string) (string, error)

// startSwarmTask validates the request, creates a task, starts the workflow,
// and returns 202 with the taskID and workflowID.
func (s *Server) startSwarmTask(
	c echo.Context,
	primitiveType sqlc.PrimitiveType,
	start workflowStarter,
) error {
	ctx := c.Request().Context()

	var req struct {
		RequestText string `json:"requestText"`
		TicketID    string `json:"ticketID"`
	}
	if err := c.Bind(&req); err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
	}
	if req.RequestText == "" {
		return echo.NewHTTPError(http.StatusBadRequest, "requestText is required")
	}

	// Auto-create a Linear ticket if none was provided.
	if req.TicketID == "" && s.LinearClient != nil {
		labels := labelsForPrimitive(primitiveType)
		identifier, createErr := s.LinearClient.CreateIssue(
			ctx,
			req.RequestText,
			linear.CreateOpts{
				Labels: labels,
				State:  "In Progress",
			},
		)
		if createErr != nil {
			s.Logger.Error("failed to auto-create Linear ticket", "error", createErr)
			return echo.NewHTTPError(
				http.StatusInternalServerError,
				"failed to create Linear ticket",
			)
		}
		req.TicketID = identifier
		s.Logger.Info("auto-created Linear ticket",
			"ticketID", identifier, "type", primitiveType)
	}

	taskID := uuid.NewString()[:8]
	now := time.Now().UTC().Format(time.RFC3339)

	if err := s.DB.CreateSwarmTask(ctx, sqlc.CreateSwarmTaskParams{
		ID:            taskID,
		PrimitiveType: primitiveType,
		RequestText:   req.RequestText,
		Status:        sqlc.TaskStatusPending,
		LinearIssueID: sql.NullString{String: req.TicketID, Valid: req.TicketID != ""},
		CreatedAt:     now,
		UpdatedAt:     now,
	}); err != nil {
		s.Logger.Error("failed to create swarm task", "error", err)
		return echo.NewHTTPError(http.StatusInternalServerError, "failed to create task")
	}

	workflowID, err := start(ctx, taskID, req.RequestText, req.TicketID)
	if err != nil {
		s.Logger.Error("failed to start workflow",
			"type", primitiveType, "taskID", taskID, "error", err)
		// Mark the task as failed so it doesn't stay orphaned in "pending".
		if statusErr := s.DB.UpdateSwarmTaskStatus(ctx, sqlc.UpdateSwarmTaskStatusParams{
			Status:    sqlc.TaskStatusFailed,
			UpdatedAt: time.Now().UTC().Format(time.RFC3339),
			ID:        taskID,
		}); statusErr != nil {
			s.Logger.Error(
				"failed to mark task as failed",
				"taskID",
				taskID,
				"error",
				statusErr,
			)
		}
		return echo.NewHTTPError(
			http.StatusInternalServerError,
			"failed to start workflow",
		)
	}

	// Store workflow ID on the task.
	if err := s.DB.UpdateSwarmTaskWorkflowID(ctx, sqlc.UpdateSwarmTaskWorkflowIDParams{
		WorkflowID: sql.NullString{String: workflowID, Valid: true},
		UpdatedAt:  time.Now().UTC().Format(time.RFC3339),
		ID:         taskID,
	}); err != nil {
		s.Logger.Error("failed to persist workflow ID", "taskID", taskID, "error", err)
		return echo.NewHTTPError(
			http.StatusInternalServerError,
			"failed to persist workflow",
		)
	}

	return c.JSON(http.StatusAccepted, map[string]string{
		"taskID":     taskID,
		"workflowID": workflowID,
		"ticketID":   req.TicketID,
	})
}

// handleSwarmStartResearch creates a research task and starts the workflow.
func (s *Server) handleSwarmStartResearch(c echo.Context) error {
	if s.SwarmManager == nil {
		return echo.NewHTTPError(
			http.StatusServiceUnavailable,
			"swarm manager not configured",
		)
	}
	return s.startSwarmTask(c, sqlc.PrimitiveTypeResearch, s.SwarmManager.StartResearch)
}

