// handleSwarmDashboardSSE provides live updates for the swarm dashboard.
func (s *Server) handleSwarmDashboardSSE(c echo.Context) error {
	r := c.Request()
	sse := datastar.NewSSE(c.Response().Writer, r)

	// The selected task and active tab are baked into the page URL;
	// SSE patches use the same values.
	selectedTaskID := c.QueryParam("task")
	activeTab := c.QueryParam("tab")
	if activeTab == "" {
		activeTab = "chat"
	}

	swarmCh := s.EventBus.Subscribe("swarm")
	defer s.EventBus.Unsubscribe("swarm", swarmCh)

	heartbeat := time.NewTicker(swarmHeartbeatInterval)
	defer heartbeat.Stop()

	for {
		select {
		case <-swarmCh:
			ctx := r.Context()
			tasks, err := s.DB.ListSwarmTasks(ctx, defaultQueryLimit)
			if err != nil {
				s.Logger.Warn("SSE: failed to list tasks", "error", err)
			}

			if err := patchSwarmSidebar(sse, tasks, selectedTaskID); err != nil {
				return nil // client disconnected
			}

			// Only patch detail pane for the user's selected task,
			// and only if it's still active (running/pending).
			if selectedTaskID != "" {
				task, err := s.DB.GetSwarmTask(ctx, selectedTaskID)
				if err == nil &&
					(task.Status == sqlc.TaskStatusRunning || task.Status == sqlc.TaskStatusPending) {
					d := s.loadTaskDetail(ctx, selectedTaskID, "SSE")
					chatMsgs := s.buildSwarmChatMessages(task, d.Messages, d.Spans)
					if err := patchSwarmDetail(
						sse,
						task,
						chatMsgs,
						d.Spans,
						d.Artifacts,
						activeTab,
					); err != nil {
						return nil // client disconnected
					}
				}
			}

		case <-heartbeat.C:
			ctx := r.Context()

			// Only send heartbeat patches if there are active tasks.
			tasks, err := s.DB.ListSwarmTasks(ctx, defaultQueryLimit)
			if err != nil {
				s.Logger.Warn("SSE heartbeat: failed to list tasks", "error", err)
			}

			hasActive := false
			for _, t := range tasks {
				if t.Status == sqlc.TaskStatusRunning ||
					t.Status == sqlc.TaskStatusPending {
					hasActive = true
					break
				}
			}
			if !hasActive {
				continue // nothing to update
			}

			if err := patchSwarmSidebar(sse, tasks, selectedTaskID); err != nil {
				return nil // client disconnected
			}

			if selectedTaskID != "" {
				task, err := s.DB.GetSwarmTask(ctx, selectedTaskID)
				if err == nil &&
					(task.Status == sqlc.TaskStatusRunning || task.Status == sqlc.TaskStatusPending) {
					d := s.loadTaskDetail(ctx, selectedTaskID, "SSE heartbeat")
					chatMsgs := s.buildSwarmChatMessages(task, d.Messages, d.Spans)
					if err := patchSwarmDetail(
						sse,
						task,
						chatMsgs,
						d.Spans,
						d.Artifacts,
						activeTab,
					); err != nil {
						return nil // client disconnected
					}
				}
			}

		case <-r.Context().Done():
			return nil
		}
	}
}

