// handleSwarmArtifactView renders an artifact as a markdown page.
func (s *Server) handleSwarmArtifactView(c echo.Context) error {
	ctx := c.Request().Context()
	artifactID := c.Param("id")

	artifact, err := s.DB.GetSwarmArtifact(ctx, artifactID)
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			return echo.NewHTTPError(http.StatusNotFound, "artifact not found")
		}
		return echo.NewHTTPError(http.StatusInternalServerError, "failed to get artifact")
	}

	// Resolve file path relative to the repo root (one level up from DataDir).
	repoRoot := filepath.Dir(s.DataDir)
	fullPath := filepath.Join(repoRoot, artifact.FilePath)

	// Security: ensure resolved path stays within repo root.
	absPath, err := filepath.Abs(fullPath)
	if err != nil {
		return echo.NewHTTPError(http.StatusInternalServerError, "failed to resolve path")
	}
	absRoot, _ := filepath.Abs(repoRoot)
	if !strings.HasPrefix(absPath, absRoot+string(filepath.Separator)) {
		return echo.NewHTTPError(http.StatusForbidden, "path traversal")
	}

	// Read file and render markdown.
	content, err := os.ReadFile(absPath)
	if err != nil {
		return echo.NewHTTPError(http.StatusNotFound, "artifact file not found")
	}
	contentHTML := s.CreateMDRenderer.MarkdownBytesToHTML(content)

	// Fetch task for context.
	var taskTitle string
	if task, taskErr := s.DB.GetSwarmTask(ctx, artifact.TaskID); taskErr == nil {
		if task.Title.Valid && task.Title.String != "" {
			taskTitle = task.Title.String
		} else {
			taskTitle = task.RequestText
		}
	}

	return render(c, swarmview.ArtifactViewPage(swarmview.ArtifactViewData{
		ArtifactID:   artifact.ID,
		ArtifactType: string(artifact.ArtifactType),
		FilePath:     artifact.FilePath,
		TaskID:       artifact.TaskID,
		TaskTitle:    taskTitle,
		ContentHTML:  contentHTML,
	}))
}

